import java.util.Scanner;

public class PrimeNumberFinder {

    /**
     * Checks if a number is prime or not.
     *
     * @param num The number to check.
     * @return true if the number is prime; false otherwise.
     */
    private boolean isPrime(int num) {
        if (num <= 1) return false; // Numbers less than or equal to 1 are not prime

        for (int i = 2; i <= Math.sqrt(num); i++) { // Check divisibility starting from 2 up to square root of num
            if (num % i == 0) return false; // Found a divisor other than 1 and itself -> Not prime
        }

        return true; // No divisors found except 1 and itself -> Is prime
    }

    public static void main(String[] args) {
        // Initialize a Scanner object to read input from the console
        Scanner scanner = new Scanner(System.in);

        // Prompt the user to enter the upper limit for generating primes
        System.out.print("Enter the upper limit for prime generation: ");
        int n = scanner.nextInt();

        // Ensure valid input greater than 1
        if (n <= 1) {
            System.err.println("Please enter a value greater than 1.");
            return;
        }

        // Print header indicating start of prime list
        System.out.println("\nThe prime numbers up to " + n + " are:");

        // Loop through numbers from 2 to n inclusive
        for (int i = 2; i <= n; i++) {
            // Use helper method 'isPrime' to determine primality
            if (new PrimeNumberFinder().isPrime(i)) {
                System.out.print(i + " "); // Output the prime number followed by space
            }
        }

        // Close the scanner after use
        scanner.close();
    }
}
